import "@/App.css";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
  Outlet,
} from "react-router-dom";

import axios from "axios";
import { useMemo } from "react";
import { Toaster } from "@/components/ui/sonner";

// ======================
// PUBLIC PAGES
// ======================
import LandingPage from "@/pages/LandingPage";
import SchoolProfilePage from "@/pages/SchoolProfilePage";

// ======================
// AUTH PAGES
// ======================
import LoginPage from "@/pages/LoginPage";
import RegisterPage from "@/pages/RegisterPage";
import JoinSchoolPage from "@/pages/JoinSchoolPage";

// ======================
// DASHBOARD LAYOUT
// ======================
import DashboardLayout from "@/components/layouts/DashboardLayout";

// ======================
// CORE MODULES
// ======================
import Dashboard from "@/pages/Dashboard";
import StudentsPage from "@/pages/StudentsPage";
import StaffPage from "@/pages/StaffPage";
import FeesPage from "@/pages/FeesPage";
import AttendancePage from "@/pages/AttendancePage";
import ExamsPage from "@/pages/ExamsPage";
import TimetablePage from "@/pages/TimetablePage";
import InventoryPage from "@/pages/InventoryPage";

// ======================
// PORTALS
// ======================
import StudentPortal from "@/pages/StudentPortal";
import TeacherPortal from "@/pages/TeacherPortal";
import FinancePortal from "@/pages/FinancePortal";
import SecretaryPortal from "@/pages/SecretaryPortal";

// ======================
// ADMIN
// ======================
import SuperAdminDashboard from "@/pages/SuperAdminDashboard";
import AnnouncementsPage from "@/pages/AnnouncementsPage";

// ======================
// DEBUG
// ======================
import DataExplorer from "@/pages/DataExplorer";

// ======================
// BACKEND CONFIG
// ======================
const BACKEND_URL =
  process.env.REACT_APP_BACKEND_URL || "http://localhost:8000";

export const API = `${BACKEND_URL.replace(/\/$/, "")}/api`;

// ======================
// AUTH SERVICE
// ======================
export const authService = {
  getToken: () => {
    try {
      return localStorage.getItem("token");
    } catch {
      return null;
    }
  },

  getUser: () => {
    try {
      const user = localStorage.getItem("user");

      if (!user || user === "undefined") {
        return null;
      }

      return JSON.parse(user);
    } catch (error) {
      console.error("Failed to parse user:", error);
      return null;
    }
  },

  setAuth: (token, user) => {
    if (!token || !user) return;

    localStorage.setItem("token", token);
    localStorage.setItem("user", JSON.stringify(user));
  },

  clearAuth: () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
  },

  isAuthenticated: () => {
    return !!localStorage.getItem("token");
  },

  getRole: () => {
    const user = authService.getUser();

    if (!user?.role) return null;

    return String(user.role).toUpperCase();
  },
};

// ======================
// AXIOS CLIENT
// ======================
export const apiClient = axios.create({
  baseURL: API,
  timeout: 30000,
});

// ======================
// REQUEST INTERCEPTOR
// ======================
apiClient.interceptors.request.use(
  (config) => {
    const token = authService.getToken();

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    config.headers["Content-Type"] = "application/json";

    return config;
  },
  (error) => Promise.reject(error)
);

// ======================
// RESPONSE INTERCEPTOR
// ======================
apiClient.interceptors.response.use(
  (response) => response,

  (error) => {
    const status = error?.response?.status;

    // Auto logout on invalid token
    if (status === 401) {
      authService.clearAuth();

      if (window.location.pathname !== "/login") {
        window.location.href = "/login";
      }
    }

    // Helpful frontend debugging
    console.error("API ERROR:", {
      url: error?.config?.url,
      method: error?.config?.method,
      status,
      data: error?.response?.data,
    });

    return Promise.reject(error);
  }
);

// ======================
// ROLE NORMALIZER
// ======================
const normalizeRole = (role) => {
  if (!role) return "";

  return String(role).trim().toUpperCase();
};

// ======================
// ROLE HOME ROUTES
// ======================
const getDefaultRouteByRole = (role) => {
  const normalized = normalizeRole(role);

  switch (normalized) {
    case "SUPER_ADMIN":
      return "/app/super-admin";

    case "SCHOOL_ADMIN":
      return "/app/dashboard";

    case "TEACHER":
      return "/app/teacher-portal";

    case "FINANCE":
      return "/app/finance-portal";

    case "SECRETARY":
      return "/app/secretary-portal";

    case "STUDENT":
      return "/app/student-portal";

    default:
      return "/app/dashboard";
  }
};

// ======================
// ROLE ACCESS MAP
// ======================
const routePermissions = {
  dashboard: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
    "TEACHER",
    "FINANCE",
    "SECRETARY",
  ],

  students: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
  ],

  staff: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],

  fees: [
    "SCHOOL_ADMIN",
    "FINANCE",
  ],

  attendance: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "SECRETARY",
  ],

  exams: [
    "SCHOOL_ADMIN",
    "TEACHER",
  ],

  timetable: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "STUDENT",
  ],

  inventory: [
    "SCHOOL_ADMIN",
    "SECRETARY",
  ],

  announcements: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
    "FINANCE",
    "STUDENT",
  ],

  "teacher-portal": [
    "TEACHER",
    "SCHOOL_ADMIN",
  ],

  "finance-portal": [
    "FINANCE",
    "SCHOOL_ADMIN",
  ],

  "secretary-portal": [
    "SECRETARY",
    "SCHOOL_ADMIN",
  ],

  "student-portal": [
    "STUDENT",
  ],

  "super-admin": [
    "SUPER_ADMIN",
  ],

  debug: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],
};

// ======================
// PROTECTED ROUTE
// ======================
const ProtectedRoute = () => {
  const token = authService.getToken();

  if (!token) {
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;
};

// ======================
// ROLE PROTECTION
// ======================
const RoleProtectedRoute = ({ routeKey, children }) => {
  const role = authService.getRole();

  const allowedRoles = routePermissions[routeKey] || [];

  if (!allowedRoles.includes(role)) {
    return (
      <Navigate
        to={getDefaultRouteByRole(role)}
        replace
      />
    );
  }

  return children;
};

// ======================
// SMART ROOT REDIRECT
// ======================
const AppRootRedirect = () => {
  const role = authService.getRole();

  return (
    <Navigate
      to={getDefaultRouteByRole(role)}
      replace
    />
  );
};

// ======================
// SAFE LAYOUT WRAPPER
// ======================
const SafeDashboardLayout = () => {
  const location = useLocation();

  const user = useMemo(() => {
    return authService.getUser();
  }, []);

  // Prevent blank dashboard crashes
  if (!user) {
    authService.clearAuth();

    return <Navigate to="/login" replace />;
  }

  return (
    <DashboardLayout
      key={location.pathname}
      currentUser={user}
    />
  );
};

// ======================
// APP
// ======================
function App() {
  return (
    <div className="App">
      <BrowserRouter>
        <Routes>

          {/* ========================= */}
          {/* PUBLIC ROUTES */}
          {/* ========================= */}

          <Route path="/" element={<LandingPage />} />

          <Route path="/login" element={<LoginPage />} />

          <Route
            path="/register"
            element={<RegisterPage />}
          />

          <Route
            path="/register-school"
            element={<RegisterPage />}
          />

          <Route
            path="/setup-school"
            element={<SchoolProfilePage />}
          />

          <Route
            path="/join-school"
            element={<JoinSchoolPage />}
          />

          <Route
            path="/join/:inviteCode"
            element={<JoinSchoolPage />}
          />

          {/* ========================= */}
          {/* PROTECTED APP */}
          {/* ========================= */}

          <Route element={<ProtectedRoute />}>

            <Route
              path="/app"
              element={<SafeDashboardLayout />}
            >

              {/* SMART ROLE REDIRECT */}
              <Route
                index
                element={<AppRootRedirect />}
              />

              {/* ========================= */}
              {/* DASHBOARD */}
              {/* ========================= */}

              <Route
                path="dashboard"
                element={
                  <RoleProtectedRoute routeKey="dashboard">
                    <Dashboard />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* STUDENTS */}
              {/* ========================= */}

              <Route
                path="students"
                element={
                  <RoleProtectedRoute routeKey="students">
                    <StudentsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* STAFF */}
              {/* ========================= */}

              <Route
                path="staff"
                element={
                  <RoleProtectedRoute routeKey="staff">
                    <StaffPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* FEES */}
              {/* ========================= */}

              <Route
                path="fees"
                element={
                  <RoleProtectedRoute routeKey="fees">
                    <FeesPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* ATTENDANCE */}
              {/* ========================= */}

              <Route
                path="attendance"
                element={
                  <RoleProtectedRoute routeKey="attendance">
                    <AttendancePage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* EXAMS */}
              {/* ========================= */}

              <Route
                path="exams"
                element={
                  <RoleProtectedRoute routeKey="exams">
                    <ExamsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* TIMETABLE */}
              {/* ========================= */}

              <Route
                path="timetable"
                element={
                  <RoleProtectedRoute routeKey="timetable">
                    <TimetablePage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* INVENTORY */}
              {/* ========================= */}

              <Route
                path="inventory"
                element={
                  <RoleProtectedRoute routeKey="inventory">
                    <InventoryPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* ANNOUNCEMENTS */}
              {/* ========================= */}

              <Route
                path="announcements"
                element={
                  <RoleProtectedRoute routeKey="announcements">
                    <AnnouncementsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* PORTALS */}
              {/* ========================= */}

              <Route
                path="student-portal"
                element={
                  <RoleProtectedRoute routeKey="student-portal">
                    <StudentPortal />
                  </RoleProtectedRoute>
                }
              />

              <Route
                path="teacher-portal"
                element={
                  <RoleProtectedRoute routeKey="teacher-portal">
                    <TeacherPortal />
                  </RoleProtectedRoute>
                }
              />

              <Route
                path="finance-portal"
                element={
                  <RoleProtectedRoute routeKey="finance-portal">
                    <FinancePortal />
                  </RoleProtectedRoute>
                }
              />

              <Route
                path="secretary-portal"
                element={
                  <RoleProtectedRoute routeKey="secretary-portal">
                    <SecretaryPortal />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* SUPER ADMIN */}
              {/* ========================= */}

              <Route
                path="super-admin"
                element={
                  <RoleProtectedRoute routeKey="super-admin">
                    <SuperAdminDashboard />
                  </RoleProtectedRoute>
                }
              />

              {/* ========================= */}
              {/* DEBUG */}
              {/* ========================= */}

              <Route
                path="debug"
                element={
                  <RoleProtectedRoute routeKey="debug">
                    <DataExplorer />
                  </RoleProtectedRoute>
                }
              />

            </Route>

          </Route>

          {/* ========================= */}
          {/* FALLBACK */}
          {/* ========================= */}

          <Route
            path="*"
            element={<Navigate to="/" replace />}
          />

        </Routes>
      </BrowserRouter>

      <Toaster
        position="top-right"
        richColors
      />
    </div>
  );
}

export default App;
